import{_ as n,o as a,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse(`{"title":"20. Superannuation","description":"","frontmatter":{"title":"20. Superannuation","eba":"Children's Services Award 2010","topics":["leave","wages","superannuation","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/wages/20-superannuation.md","filePath":"ebas/childrens-services/wages/20-superannuation.md"}`),o={name:"ebas/childrens-services/wages/20-superannuation.md"};function i(s,e,u,p,l,d){return a(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="_20-superannuation" tabindex="-1">20. Superannuation <a class="header-anchor" href="#_20-superannuation" aria-label="Permalink to &quot;20. Superannuation&quot;">​</a></h1><ol><li>Superannuation legislation</li></ol><p>a. The <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">[NES]{.underline}</a> and Superannuation legislation, including the <em>Superannuation Guarantee (Administration) Act 1992</em> (Cth), the <em>Superannuation Guarantee Charge Act 1992</em> (Cth), the <em>Superannuation Industry (Supervision) Act 1993</em> (Cth) and the <em>Superannuation (Resolution of Complaints) Act 1993</em> (Cth), deal with the superannuation rights and obligations of employers and employees.</p><p>b. The rights and obligations in clause 20 supplement those in superannuation legislation and the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">[NES]{.underline}</a>.</p><p>NOTE: Under superannuation legislation:</p><p>(a) Individual employees generally have the opportunity to choose their own superannuation fund.</p><p>(b) If a new employee does not choose a superannuation fund, the employer must ask the Australian Taxation Office (ATO) whether the employee is an existing member of a stapled superannuation fund and, if stapled fund details are provided by the ATO, make contributions to the stapled fund.</p><p>(c) If an employee does not choose a superannuation fund and does not have a stapled fund, the choice of superannuation fund requirements will be satisfied by contributions made to a superannuation fund nominated in the award covering the employee, provided the fund is able to accept contributions for the benefit of the employee.</p><p>(d) A fund may not be able to accept contributions for the benefit of an employee if the employee would be a new member of the fund&#39;s MySuper product and the MySuper product is closed to new members because it has failed the performance tests of Australian Prudential Regulation Authority (APRA) for 2 consecutive years.</p><ol><li>Employer contributions</li></ol><p>An employer must make such superannuation contributions to a superannuation fund for the benefit of an employee as will avoid the employer being required to pay the superannuation guarantee charge under superannuation legislation with respect to that employee.</p><ol><li><p>Voluntary employee contributions</p><p>a. Subject to the governing rules of the relevant superannuation fund, an employee may, in writing, authorise their employer to pay on behalf of the employee a specified amount from the post-taxation wages of the employee into the same superannuation fund as the employer makes the superannuation contributions provided for in clause 20.1(a).</p><p>b. An employee may adjust the amount the employee has authorised their employer to pay from the wages of the employee from the first of the month following the giving of three months&#39; written notice to their employer.</p><p>c. The employer must pay the amount authorised under clauses 20.3(a) or (b) no later than 28 days after the end of the month in which the deduction authorised under clauses 20.3(a) or (b) was made.</p></li><li><p>Superannuation fund</p></li></ol><p>Unless, to comply with superannuation legislation, the employer is required to make the superannuation contributions provided for in clause 20.1(a) to another superannuation fund, the employer must make the superannuation contributions provided for in clause 20.1(a) and pay any amount authorised under clauses 20.3(a) or 20.3(b) to one of the following superannuation funds or its successor, provided that, in respect of new employees, the fund is able to accept new beneficiaries:</p><p>a. HESTA Super Fund;</p><p>[20.4(b) substituted by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR530219.htm" target="_blank" rel="noreferrer">PR530219</a> ppc 26Oct12]</p><p>b. CareSuper;</p><p>c. AustralianSuper;</p><p>d. Tasplan;</p><p>[20.4(e) varied by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR743360.htm" target="_blank" rel="noreferrer">PR743360</a> ppc 07Jul22]</p><p>e. Hostplus;</p><p>[20.4(f) deleted by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR546127.htm" target="_blank" rel="noreferrer">PR546127</a> ppc 01Jan14]</p><p>[20.4(g) renumbered as 20.4(f) by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR546127.htm" target="_blank" rel="noreferrer">PR546127</a> ppc 01Jan14]</p><p>f. Queensland Independent Education and Care Superannuation Trust (QIEC Super);</p><p>[20.4(h) renumbered as 20.4(g) by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR546127.htm" target="_blank" rel="noreferrer">PR546127</a> ppc 01Jan14]</p><p>g. Sunsuper;</p><p>[20.4(i) renumbered as 20.4(h) by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR546127.htm" target="_blank" rel="noreferrer">PR546127</a> ppc 01Jan14]</p><p>h. Australian Childcare Super Fund;</p><p>[20.4(j) renumbered as 20.4(i) and varied by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR546127.htm" target="_blank" rel="noreferrer">PR546127</a> ppc 01Jan14]</p><p>i. any superannuation fund to which the employer was making superannuation contributions for the benefit of its employees before 12 September 2008, provided the superannuation fund is an eligible choice fund and is a fund that offers a MySuper product or is an exempt public sector scheme; or</p><p>j. a superannuation fund or scheme which the employee is a defined benefit member of.</p><ol><li>Absence from work</li></ol><p>Subject to the governing rules of the relevant superannuation fund, the employer must also make the superannuation contributions provided for in clause 20.1(a) and pay the amount authorised under clauses 20.3(a) or (b):</p><p>a. <strong>Paid leave</strong>---while the employee is on any paid leave;</p><p>b. <strong>Work-related injury or illness</strong>---for the period of absence from work (subject to a maximum of 52 weeks) of the employee due to work-related injury or work-related illness provided that:</p><pre><code>i.  the employee is receiving workers compensation payments or is
    receiving regular payments directly from the employer in
    accordance with the statutory requirements; and

ii. the employee remains employed by the employer.
</code></pre><p>Plain language terms: super, SG.</p>`,36)])])}const c=n(o,[["render",i]]);export{m as __pageData,c as default};
